import clsx from 'clsx';
import stylex from '@universe-design/stylex';
import * as React from 'react';
import { ListBox } from '../../shared/components/list/List';
import { useTransferContext } from '../hooks/TransferContext';
import type { TransferPanelContextType } from '../hooks/PanelContext';
import { TransferPanelProvider } from '../hooks/PanelContext';
import { forwardHTMLRef } from '../../util/forwardRef';
import { sxPanel, sxPanelHeader } from '../sx';

export const TransferPanelHeader = forwardHTMLRef<unknown, 'div'>((props, ref) => {
  const { children, className, ...htmlProps } = props;
  const { cssScope } = useTransferContext();

  return (
    <div className={clsx(cssScope('__panel__header'), stylex(sxPanelHeader), className)} {...htmlProps} ref={ref}>
      {children}
    </div>
  );
});

export const PanelContainer = forwardHTMLRef<Pick<TransferPanelContextType, 'optionRenderer' | 'emptyContent'>, 'div'>(
  ({ children, className, emptyContent, optionRenderer, ...htmlProps }, ref) => {
    const { cssScope } = useTransferContext();

    return (
      <TransferPanelProvider
        value={{
          emptyContent,
          optionRenderer,
        }}
      >
        <ListBox sx={[sxPanel]} className={clsx(className, cssScope('__panel'))} {...htmlProps} ref={ref}>
          {children}
        </ListBox>
      </TransferPanelProvider>
    );
  },
);
